import React, { useState } from 'react';
import '../styles/Katalog.css';

const Katalog = () => {
  const [produk] = useState([
    { id: 1, nama: 'Black Forest Cake', harga: 'Rp 150.000', img: 'https://images.unsplash.com/photo-1606890737304-57a1ca8a5b62?auto=format&fit=crop&q=80' },
    { id: 2, nama: 'Cheesecake', harga: 'Rp 85.000', img: 'https://images.unsplash.com/photo-1533134242443-d4fd215305ad?auto=format&fit=crop&q=80' },
    { id: 3, nama: 'Tiramisu Dessert Box', harga: 'Rp 45.000', img: 'https://images.unsplash.com/photo-1571115177098-24edf3e00b65?auto=format&fit=crop&q=80' },
    { id: 4, nama: 'Nastar Keju Premium', harga: 'Rp 120.000', img: 'https://images.unsplash.com/photo-1605335967732-2b6389fccb8c?auto=format&fit=crop&q=80' },
    { id: 5, nama: 'Red Velvet Cake', harga: 'Rp 140.000', img: 'https://images.unsplash.com/photo-1616541823729-00fe0aacd32c?auto=format&fit=crop&q=80' },
    { id: 6, nama: 'Bolu Cukke\'', harga: 'Rp 60.000', img: 'https://images.unsplash.com/photo-1587241321921-91a834d6d191?auto=format&fit=crop&q=80' }
  ]);

  return (
    <div className="katalog-wrapper">
      <div className="katalog-overlay"></div>
      
      <div className="katalog-content">
        <aside className="sidebar">
          <h3>Kategori</h3>
          <div className="category-item active">Semua Produk</div>
          <div className="category-item highlight">Kue Ulang Tahun</div>
          <div className="category-item">Dessert Box</div>
          <div className="category-item">Kue Kering</div>
        </aside>

        <div className="product-grid">
          {produk.map((kue) => (
            <div key={kue.id} className="product-card">
              <img src={kue.img} alt={kue.nama} className="product-image" />
              <div className="product-info">
                <p className="product-name">{kue.nama}</p>
                <p className="product-price">{kue.harga}</p>
                <button className="btn-add">+ Masukkan Keranjang</button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default Katalog;
